namespace sv_b6de1ffe6cc64d10815e25fdbc22efbe.Services;

public sealed record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 30),
            new(2, "Risotto alla Milanese", "Creamy saffron risotto from Milan.", 45),
            new(3, "Tiramisu", "Layered coffee-flavoured Italian dessert.", 25),
        },
        [2] = new List<Recipe>
        {
            new(4, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts and vegetables.", 20),
            new(5, "Mapo Tofu", "Silken tofu in a fiery Sichuan chili sauce.", 15),
            new(6, "Char Siu", "Cantonese-style barbecued pork with honey glaze.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple and cilantro.", 35),
            new(8, "Mole Poblano", "Rich chocolate-chili sauce served over chicken.", 90),
            new(9, "Elote", "Grilled Mexican street corn with mayo and cotija cheese.", 10),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate slow API call
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in GetSortedRecipes())
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <small>(@recipe.PrepTimeMinutes min)</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload when the cuisine actually changes
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // Verify we weren't cancelled while awaiting
            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was intentionally cancelled — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes,
        };
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

